window.__QUIZ_DATA__=[{"id":"objective>English Language>2020>1","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"In the folowing sentences, there is one underlined word, choose the one most  nearly opposite in meaning to the underlined word and will fill in the gap in the sentence    A guest should not make derogatory remarks about what he is offered by his host but _______ statement.","images":[],"options":{"A":"candid","B":"appealing","C":"polite","D":"complimentary"},"answer":"D","explanation":"-\tDerogatory simply means showing a critical or disrespectful attitude tending to lessen the merit or reputation of a person or thing while Complimentary means expressing an appreciation; praising or approving.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>2","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"In the folowing sentences, there is one underlined word, choose the one most  nearly opposite in meaning to the underlined word and will fill in the gap in the sentence  The audience applauded the last speaker, but the first was ________.","images":[],"options":{"A":"booed","B":"rejected","C":"abused","D":"scorned"},"answer":"A","explanation":"Applauded means show approval or praise by clapping while, booed means to show disapproval of a speaker or performer.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>3","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"In the folowing sentences, there is one underlined word, choose the one most  nearly opposite in meaning to the underlined word and will fill in the gap in the sentence  The commander said that raw recruits could not dislodge the enemies, he needed _______ men.","images":[],"options":{"A":"skilled","B":"practical","C":"learned","D":"seasoned"},"answer":"D","explanation":"The word 'raw' in this context refers to someone inexperienced or new. The opposite would be someone experienced or seasoned. Therefore, the correct answer is 'seasoned'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>4","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"In the folowing sentences, there is one underlined word, choose the one most  nearly opposite in meaning to the underlined word and will fill in the gap in the sentence  John gave a fictitious account of the incident but his sins account was _______.","images":[],"options":{"A":"probable","B":"compelling","C":"factual","D":"necessary"},"answer":"C","explanation":"The word 'fictitious' means something that is invented or untrue. The opposite of this would be something that is true or factual. Therefore, the correct answer is 'factual'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>5","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"In the folowing sentences, there is one underlined word, choose the one most  nearly opposite in meaning to the underlined word and will fill in the gap in the sentence  While the refuse dump smelled fetid, the orchard exuded a _______ smell.","images":[],"options":{"A":"fragrant","B":"spicy","C":"clean","D":"dry"},"answer":"A","explanation":"The word 'fetid' means having an offensive smell. The opposite of 'fetid' would be a word that describes a pleasant smell. Among the given options, 'fragrant' is the word that describes a pleasant smell. Therefore, the correct answer is 'fragrant'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>6","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"In the folowing sentences, there is one underlined word, choose the one most  nearly opposite in meaning to the underlined word and will fill in the gap in the sentence  Only some of the accused were acquitted, the rest were ________.","images":[],"options":{"A":"remanded","B":"convicted","C":"detained","D":"interdicted"},"answer":"B","explanation":"Acquitted means relieve from a charge of crime; declare not guilty while convicted means declared guilty of a criminal offence.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>7","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"In the folowing sentences, there is one underlined word, choose the one most  nearly opposite in meaning to the underlined word and will fill in the gap in the sentence  The principal chastened Ben for his use of coarse language and advised him to emulate his sister's ________ behaviour.","images":[],"options":{"A":"pure","B":"neat","C":"refined","D":"organised"},"answer":"C","explanation":"The word 'coarse' in this context refers to something that is rough or crude. The opposite of 'coarse' in this context would be 'refined', which means elegant or cultured. Therefore, the sister's behavior is described as 'refined'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>8","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"In the folowing sentences, there is one underlined word, choose the one most  nearly opposite in meaning to the underlined word and will fill in the gap in the sentence  It would have been my pleasure to accept your invitation but I have to ______ it because of previous engagement.","images":[],"options":{"A":"jettison","B":"differ","C":"suspend","D":"decline"},"answer":"D","explanation":"The suitable opposite in meaning is decline which means to politely refuse (especially an invitation).","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>9","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"In the folowing sentences, there is one underlined word, choose the one most  nearly opposite in meaning to the underlined word and will fill in the gap in the sentence  Other people are expected to be _______ where youths are green.","images":[],"options":{"A":"experienced","B":"cautious","C":"equipped","D":"considerate"},"answer":"A","explanation":"If you say that someone is green, it mean that such a person have had very little experience of life or on a particular job. Therefore, its opposite is experienced.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>10","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : CLAUSES","question":"I accidentally stepped on my brother but he told mummy I did it ________.","images":[],"options":{"A":"thoughtfully","B":"intuitively","C":"deliberately","D":"annoyingly"},"answer":"C","explanation":"Accidentally means by chance or inadvertently. Deliberately means consciously and intentionally that is, on purpose.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>11","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the words that best complete each of the following sentences    The runner was _____ at fifteen seconds at the end of the race.","images":[],"options":{"A":"taped","B":"timed","C":"belled","D":"flagged"},"answer":"B","explanation":"In the context of a race, the term 'timed' is used to indicate the measurement of the time taken by a runner to complete the race. 'Taped', 'belled', and 'flagged' do not fit into this context.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>12","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the words that best complete each of the following sentences  The appellant court has ________ the decision of the lower court.","images":[],"options":{"A":"obstructed","B":"nullified","C":"neutralized","D":"balanced"},"answer":"B","explanation":"In legal terms, when an appellate court 'nullifies' the decision of a lower court, it means that the decision of the lower court is declared legally void and has no force or effect. 'Obstructed', 'neutralized', and 'balanced' do not fit into this context.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>13","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the words that best complete each of the following sentences  The defeated boxer left the ring looking extremely ________.","images":[],"options":{"A":"dislocated","B":"distorted","C":"deserted","D":"dejected"},"answer":"D","explanation":"The correct word to complete the sentence is 'dejected'. The word 'dejected' means sad and depressed, which is a suitable description for a defeated boxer. 'Dislocated' refers to something being moved out of place, 'distorted' means twisted out of a natural, normal, or original shape or condition, and 'deserted' means abandoned, none of which accurately describe the boxer's state.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>14","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the words that best complete each of the following sentences  There is an election _______ pending against the senator.","images":[],"options":{"A":"application","B":"appeal","C":"petition","D":"complaint"},"answer":"C","explanation":"The correct word to complete the sentence is 'petition'. In the context of politics, a 'petition' is a formal written request, typically one signed by many people, appealing to authority in respect of a particular cause. In this case, the cause is an election issue against the senator. 'Application' and 'complaint' do not fit the context, and 'appeal' is not the correct term used in the context of elections.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>15","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the words that best complete each of the following sentences  The manager was not in when Addo called, so he left his _________ card.","images":[],"options":{"A":"supplementary","B":"complimentary","C":"complementary","D":"identification"},"answer":"D","explanation":"In this context, the correct word to use is 'identification'. An identification card is a card giving identifying data about a person, as full name, address, age, and color of hair and eyes, and often containing a photograph. This is what Addo would have left when the manager was not in.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>16","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the words that best complete each of the following sentences  Coming from the kitchen was the sweet _________ of mummy soup.","images":[],"options":{"A":"aroma","B":"odour","C":"fragrance","D":"scent"},"answer":"A","explanation":"The correct word to use in this context is 'aroma'. Aroma is a pleasant and distinctive smell, usually used in the context of food and drink. Therefore, it is the most appropriate word to describe the smell of mummy's soup.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>17","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the words that best complete each of the following sentences  There is a need to raise teachers salary in order to boost their _______.","images":[],"options":{"A":"spirit","B":"morale","C":"soul","D":"scent"},"answer":"B","explanation":"Morale means the confidence, enthusiasm, and discipline of a person or group at a particular time. Not moral, it means the principles of right and wrong behavior.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>18","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the words that best complete each of the following sentences  The librarian has not entered the new books in the __________.","images":[],"options":{"A":"catalogue","B":"roster","C":"list","D":"directory"},"answer":"A","explanation":"The correct word to complete the sentence is 'catalogue'. In the context of a library, a catalogue is a complete list of items, arranged systematically, usually in alphabetical or numerical order. The librarian enters new books into the catalogue so that they can be easily located by library users.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>19","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : PHRASES","question":"Choose the words that best complete each of the following sentences  The textbook is very costly, I cannot _________ it to my students.","images":[],"options":{"A":"commit","B":"afford","C":"endorse","D":"recommend"},"answer":"B","explanation":"The correct word to complete the sentence is 'afford'. In this context, 'afford' means having enough money to pay for something. The sentence implies that the textbook is too expensive for the speaker to buy for their students.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>20","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : PHRASES","question":"Choose the words that best complete each of the following sentences  The weather is too hot, I need some water to ________ my thirst.","images":[],"options":{"A":"wet","B":"quench","C":"cool","D":"soak"},"answer":"B","explanation":"The correct word to complete the sentence is 'quench'. In this context, 'quench' means to satisfy one's thirst. The sentence implies that the speaker is thirsty due to the hot weather and needs water to satisfy their thirst.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>21","subject":"English Language","year":"2020","type":"Objective","topic":"COMPREHENSION","question":"Choose the interpretation that is most appropriate.    My mother once told me that old habits die hard. This means that old habits are _______.","images":[],"options":{"A":"easily corrected","B":"difficult to change","C":"short-lived","D":"forever changing"},"answer":"B","explanation":"Old habits die hard means it is hard to stop doing things that one has been doing for a long time. Therefore, difficult to change is a suitable interpretation.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>22","subject":"English Language","year":"2020","type":"Objective","topic":"COMPREHENSION","question":"Choose the interpretation that is most appropriate.   If you ask him to sing, he will do it at the drop of a hat. This means that he will sing _________.","images":[],"options":{"A":"joyfully","B":"melodiously","C":"immediately","D":"sluggishly"},"answer":"C","explanation":"The phrase 'at the drop of a hat' is an idiom that means to do something immediately without any hesitation. Therefore, if you ask him to sing, he will do it immediately.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>23","subject":"English Language","year":"2020","type":"Objective","topic":"COMPREHENSION","question":"Choose the interpretation that is most appropriate.   The man has lost a lot and he only keeps up appearance by driving a big car. This means that the man _________.","images":[],"options":{"A":"intends to work harder","B":"pretends that all is well","C":"wants everyone to see him","D":"wants to please his people"},"answer":"B","explanation":"The phrase 'keeps up appearance' means to pretend or make it seem like everything is fine when it is not. In this context, the man is using a big car to give the impression that he is doing well, even though he has lost a lot. Therefore, the most appropriate interpretation is that the man 'pretends that all is well'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>24","subject":"English Language","year":"2020","type":"Objective","topic":"COMPREHENSION","question":"Choose the interpretation that is most appropriate.   The game was tough but our team lost by a whisker. This means that our team lost by ________.","images":[],"options":{"A":"default","B":"a wide margin","C":"not preparing well","D":"a narrow margin"},"answer":"D","explanation":"The phrase 'lost by a whisker' is an idiomatic expression that means to lose by a very small margin. Therefore, the most appropriate interpretation is that the team 'lost by a narrow margin'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>25","subject":"English Language","year":"2020","type":"Objective","topic":"COMPREHENSION","question":"Choose the interpretation that is most appropriate.   When the result was announced, it was discovered that Bimbo and Pam were neck and neck. This means that Bimbo and Pam ________.","images":[],"options":{"A":"had almost the same result","B":"failed badly","C":"had equal result","D":"passed well"},"answer":"A","explanation":"The phrase 'neck and neck' is an idiom that means two competitors are at an equal position or have almost the same result. It is often used to describe a situation where two or more competitors are so close to each other in a competition that it is difficult to predict the winner. Therefore, the most appropriate interpretation of the sentence 'When the result was announced, it was discovered that Bimbo and Pam were neck and neck' is that Bimbo and Pam had almost the same result.","marks":"1","difficulty":"1"},{"id":"objective>English Language>2020>26","subject":"English Language","year":"2020","type":"Objective","topic":"COMPREHENSION","question":"Choose the interpretation that is most appropriate.   The old woman's birthday was marked by her child with pomp. This means that the birthday was _________.","images":[],"options":{"A":"greatly celebrated","B":"remembered fondly","C":"widely advertised","D":"filmed and played back"},"answer":"A","explanation":"Pomp means impressive and colourful ceremonies, especially traditional ceremonies on public occasions.","marks":"1","difficulty":"1"},{"id":"objective>English Language>2020>27","subject":"English Language","year":"2020","type":"Objective","topic":"COMPREHENSION","question":"Choose the interpretation that is most appropriate.   When the man was accused of stealing the money, nobody raised an eyebrow. This means that nobody was ________.","images":[],"options":{"A":"sad","B":"pleased","C":"interested","D":"surprised"},"answer":"D","explanation":"The phrase 'nobody raised an eyebrow' is an idiomatic expression that means no one was surprised or showed any reaction. Therefore, the most appropriate interpretation is that nobody was surprised.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>28","subject":"English Language","year":"2020","type":"Objective","topic":"COMPREHENSION","question":"Choose the interpretation that is most appropriate.   People do not often rely on men who allow their exalted position to go to their head. This means that people shun those who ________.","images":[],"options":{"A":"are highly placed","B":"are conceited because of their position","C":"are rude because of their position","D":"do not do their work"},"answer":"B","explanation":"If something goes to someone's head, it makes that person think that they are very important or proud.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>29","subject":"English Language","year":"2020","type":"Objective","topic":"COMPREHENSION","question":"Choose the interpretation that is most appropriate.   The manager hit his roof when he was presented with the estimate for the new project. This means that the manager _________.","images":[],"options":{"A":"mobilized the worker","B":"became very angry","C":"became very suspicious","D":"cancelled the project"},"answer":"B","explanation":"The phrase 'hit the roof' is an idiomatic expression in English language which means to become very angry. Therefore, in the context of the question, the manager became very angry when he was presented with the estimate for the new project.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>30","subject":"English Language","year":"2020","type":"Objective","topic":"COMPREHENSION","question":"Choose the interpretation that is most appropriate.   When he received the news that he had lost tthe election, he did not bat an eyelid. This means that he __________.","images":[],"options":{"A":"expected to lose the election","B":"stood perfectly well","C":"was shocked to have lost the election","D":"showed no feelings."},"answer":"D","explanation":"Bat an eyelid means to display a subtle emotional reaction, such as consternation, annoyance, sadness, joy, etc.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>31","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose words that is nearest in meaning with the underlined word as it is used in the sentence.    The boy was reluctant to carry out the order of his senior.","images":[],"options":{"A":"adamant","B":"slow","C":"sluggish","D":"unwilling"},"answer":"D","explanation":"The word 'reluctant' in the context of the sentence means being unwilling or disinclined to do something. Therefore, the word 'unwilling' is the nearest in meaning to 'reluctant'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>32","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose words that is nearest in meaning with the underlined word as it is used in the sentence.  Dr Azeez declined the offer to chair the meeting.","images":[],"options":{"A":"rescinded","B":"shunned","C":"refused","D":"avoided"},"answer":"C","explanation":"The word 'declined' in the context of the sentence means to politely refuse (an invitation or suggestion). Therefore, the word 'refused' is the nearest in meaning to 'declined'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>33","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose words that is nearest in meaning with the underlined word as it is used in the sentence.  The match came to an abrupt end when the rain started.","images":[],"options":{"A":"sharp","B":"brisk","C":"quick","D":"sudden"},"answer":"D","explanation":"The word 'abrupt' in the context of the sentence means 'sudden' or 'unexpected'. It refers to something happening without warning or in a short amount of time. Therefore, the option that is nearest in meaning to 'abrupt' is 'sudden'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>34","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose words that is nearest in meaning with the underlined word as it is used in the sentence.  The boy came through the window as stealthily as he could.","images":[],"options":{"A":"quietly","B":"carefully","C":"quickly","D":"slowly"},"answer":"A","explanation":"The word 'stealthily' means to do something in a cautious and surreptitious manner, so as not to be seen or heard. Therefore, the option that is nearest in meaning to 'stealthily' is 'quietly'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>35","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose words that is nearest in meaning with the underlined word as it is used in the sentence.  Bimbo was satisfied with the result she got.","images":[],"options":{"A":"positive","B":"surprise","C":"contented","D":"appeased"},"answer":"C","explanation":"It means to be pleased because you have got what you wanted, or because something has happened in the way that you wanted. A synonymn is contented.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>36","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose words that is nearest in meaning with the underlined word as it is used in the sentence.  It is absurd that people find it difficult to be honest.","images":[],"options":{"A":"strange","B":"abnormal","C":"alarming","D":"interesting"},"answer":"A","explanation":"The word 'absurd' in the context of the sentence means that it is illogical or unreasonable that people find it difficult to be honest. Therefore, the word that is nearest in meaning to 'absurd' is 'strange'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>37","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose words that is nearest in meaning with the underlined word as it is used in the sentence.  Even a mediocre student can pass the test.","images":[],"options":{"A":"dull","B":"fresh","C":"average","D":"lazy"},"answer":"C","explanation":"The word 'mediocre' is used to describe something that is average or not very good. Therefore, the word 'average' is the nearest in meaning to 'mediocre'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>38","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose words that is nearest in meaning with the underlined word as it is used in the sentence.  We called the carpenter to repair the broken door.","images":[],"options":{"A":"restore","B":"renovate","C":"replace","D":"mend"},"answer":"D","explanation":"The word 'repair' means to fix something that is broken or damaged. Therefore, the word 'mend' is the nearest in meaning to 'repair'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>39","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose words that is nearest in meaning with the underlined word as it is used in the sentence.  Mrs Okpala gave the drunk a contemptuous look.","images":[],"options":{"A":"happy","B":"sorrowful","C":"knowing","D":"scornful"},"answer":"D","explanation":"The word 'contemptuous' means showing or expressing contempt or disdain; scornful; disrespectful. Therefore, the word that is nearest in meaning to 'contemptuous' is 'scornful'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>40","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose words that is nearest in meaning with the underlined word as it is used in the sentence.  The vice chancellor's speech at the occasion was misconstrued.","images":[],"options":{"A":"misrepresented","B":"misquoted","C":"misunderstood","D":"misreported"},"answer":"C","explanation":"The word 'misconstrued' means to interpret (something, especially a person's words or actions) wrongly. Therefore, the word that is nearest in meaning to 'misconstrued' is 'misunderstood'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>41","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : PHRASES","question":"Choose the word or group of words that best completes each of the following sentence.    The soldiers lay _______ the town to arrest the terrorist.","images":[],"options":{"A":"siege on","B":"siege to","C":"siege with","D":"siege by"},"answer":"B","explanation":"- Siege to:  If police, soldiers, or journalists lay siege to a place, it means they surround it in order to force the people there to come out or give up control of the place.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>42","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : PHRASES","question":"Choose the word or group of words that best completes each of the following sentence.  Power has been restored ________ many parts of the town.","images":[],"options":{"A":"to","B":"in","C":"for","D":"with"},"answer":"A","explanation":"The correct preposition to use after 'restored' in this context is 'to'. 'Restored to' means to bring back or reestablish something to a former place or condition.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>43","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : CLAUSES","question":"Choose the word or group of words that best completes each of the following sentence.  We got to the hall after the play _______ started.","images":[],"options":{"A":"is","B":"had","C":"have","D":"was"},"answer":"B","explanation":"The correct answer is 'had'. In this context, the past perfect tense 'had started' is used because the action of the play starting happened before another action in the past, which is 'we got to the hall'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>44","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : CLAUSES","question":"Choose the word or group of words that best completes each of the following sentence.  The woman said the maid should ________ all the plates before going to bed.","images":[],"options":{"A":"wash out","B":"wash up","C":"wash off","D":"wash away"},"answer":"B","explanation":"The correct answer is 'wash up'. In English, 'wash up' is a phrasal verb that means to clean the dishes after a meal. The other options do not fit the context of the sentence.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>45","subject":"English Language","year":"2020","type":"Objective","topic":"COMPREHENSION","question":"Choose the word or group of words that best completes each of the following sentence.  John, would you mind lifting the box? ___________.","images":[],"options":{"A":"Yes, I do","B":"No, I wouldn't","C":"Yes, I wouldn't","D":"No, I don't"},"answer":"B","explanation":"A tag question is a special construction in English. It is a statement followed by a mini-question. The basic structure of a tag question is: (i) A positive statement takes a negative tag (ii) A negative statement takes a positive tag. Additionally, you do not use yes with the negative nor no with the positive.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>46","subject":"English Language","year":"2020","type":"Objective","topic":"COMPREHENSION","question":"Choose the word or group of words that best completes each of the following sentence.  It was a long poem, but Rasheed learnt it _______","images":[],"options":{"A":"from memory","B":"to memory","C":"by heart","D":"to heart"},"answer":"C","explanation":"- By Heart: If you know something such as a poem by heart, it means you have learnt it so well that you can remember without having to read it.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>47","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : CLAUSES","question":"Choose the word or group of words that best completes each of the following sentence.  Let's begin all over again, _______?","images":[],"options":{"A":"may we","B":"shall we","C":"can we","D":"must we"},"answer":"B","explanation":"The correct phrase to use in this context is 'shall we'. 'Shall we' is a tag question used to suggest or propose something. It is used at the end of a sentence to seek agreement or confirmation. In this case, 'Let's begin all over again, shall we?' is a polite way of suggesting that we should start again.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>48","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : CLAUSES","question":"Choose the word or group of words that best completes each of the following sentence.  Something must be wrong with the school driver: he is ____________ today.","images":[],"options":{"A":"rather driving carefully","B":"carelessly driving rather","C":"driving rather carelessly","D":"rather carelessly driving"},"answer":"C","explanation":"The correct phrase to use in this context is 'driving rather carelessly'. The adverb 'rather' is used to indicate a degree or extent. It is usually placed before the adjective or adverb it modifies. Therefore, 'he is driving rather carelessly' means that the school driver is driving to a fairly high degree of carelessness.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>49","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : CLAUSES","question":"Choose the word or group of words that best completes each of the following sentence.  What I admire about our football team is that they love _________.","images":[],"options":{"A":"themselves","B":"one another","C":"the other","D":"ourselves"},"answer":"B","explanation":"One another is used to show that each person in a group of two or more people does something to the others.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>50","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : CLAUSES","question":"Choose the word or group of words that best completes each of the following sentence.  This is the teacher _______ told me the answer.","images":[],"options":{"A":"whom I  said","B":"who I said","C":"who I said he","D":"I said that he"},"answer":"A","explanation":"- Whom I said is the appropriate relative clause that best completes the sentence.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>51","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : CLAUSES","question":"Choose the word or group of words that best completes each of the following sentence.  Mary shouldn't have disobeyed the teacher, ----------?","images":[],"options":{"A":"should she","B":"didn't she","C":"did she","D":"could she"},"answer":"A","explanation":"A tag question is a special construction in English. It is a statement followed by a mini-question. The basic structure of a tag question is: (i) A positive statement takes a negative tag (ii) A negative statement takes a positive tag","marks":"1","difficulty":"1"},{"id":"objective>English Language>2020>52","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : CLAUSES","question":"Choose the word or group of words that best completes each of the following sentence.  She wondered if the water was not _____ hot for drinking.","images":[],"options":{"A":"very","B":"so","C":"much","D":"too"},"answer":"D","explanation":"\"Too\" is an adverb of degree to indicate a higher degree than it is desirable, permissible, or excessively.","marks":"1","difficulty":"1"},{"id":"objective>English Language>2020>53","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : PREPOSITIONS","question":"Choose the word or group of words that best completes each of the following sentence.  I told him not to play _______ fire.","images":[],"options":{"A":"on","B":"with","C":"beneath","D":"upon"},"answer":"B","explanation":"The correct preposition to use after 'play' in this context is 'with'. So, the correct sentence is 'I told him not to play with fire.' This is a common English idiom that means to do something dangerous or risky.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>54","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : ADVERBS","question":"Choose the word or group of words that best completes each of the following sentence.  We enjoyed ourselves ______ much at the party.","images":[],"options":{"A":"too","B":"that","C":"as","D":"very"},"answer":"D","explanation":"The correct adverb to use in this context is 'very'. So, the correct sentence is 'We enjoyed ourselves very much at the party.' The adverb 'very' is used to give more emphasis to the adjective or adverb that it modifies, in this case, 'much'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>55","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : PHRASES","question":"Choose the word or group of words that best completes each of the following sentence.  You will need to commit the formula _______ memory.","images":[],"options":{"A":"to","B":"in","C":"for","D":"by"},"answer":"A","explanation":"The correct preposition to use after 'commit' in this context is 'to'. When you 'commit something to memory', it means you learn it so well that you can remember it perfectly.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>56","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : PHRASES","question":"Choose the word or group of words that best completes each of the following sentence.  The usher told the people to _______  their shoes before they enter the hall.","images":[],"options":{"A":"put off","B":"put out","C":"take off","D":"take out"},"answer":"C","explanation":"- We take off shoes not \"PUT OFF\" which means to cancel a meeting or an arrangement that you have made with somebody.  To take something off means to remove something, especially clothes.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>57","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : CLAUSES","question":"Choose the word or group of words that best completes each of the following sentence.  The book is neither __________.","images":[],"options":{"A":"his or yours","B":"his not yours","C":"his nor yours","D":"his own nor yours"},"answer":"C","explanation":"The correct phrase to use in this context is 'neither his nor yours'. The conjunction 'neither...nor' is used to connect two or more negative alternatives. In this case, the book does not belong to 'him' or 'you'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>58","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : PHRASES","question":"Choose the word or group of words that best completes each of the following sentence.  The boy vomited a lot on the journey; the doctor told us he suffered from __________.","images":[],"options":{"A":"travel sickness","B":"travelling sickness","C":"travel sicknesses","D":"traveller sickness"},"answer":"A","explanation":"- Travel sickness : a feeling of illness, especially of needing to vomit, that some people get in a moving vehicle.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>59","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : PHRASES","question":"Choose the word or group of words that best completes each of the following sentence.  The man gave the girl a ________ fountain pen.","images":[],"options":{"A":"small new blue","B":"blue small new","C":"blue new small","D":"new small blue"},"answer":"A","explanation":"The order of Adjectives is the sequence used when there is more than one adjective to describe a noun. Generally, the adjective order in English is:  -\tQuantity or number  -\tQuality or opinion  -\tSize  -\tAge  -\tShape  -\tColor  -\tProper adjective (often nationality, other place of origin, or material)  -\tPurpose or qualifier","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>60","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : CLAUSES","question":"Choose the word or group of words that best completes each of the following sentence.  I realized that I _______ you before.","images":[],"options":{"A":"had met","B":"met","C":"have met","D":"meet"},"answer":"A","explanation":"\"Had met\" best completes the sentence. This best suits the question.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>61","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the word or group of words that best completes each of the following sentence.  The boy had been warned not to _______ the money given to him.","images":[],"options":{"A":"loosen","B":"loose","C":"lost","D":"lose"},"answer":"D","explanation":"To lose something is to no longer have something because you do not know where it is, or because it has been taken away from you.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>62","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the word or group of words that best completes each of the following sentence.  The police officer was sacked because he gave _______ the command's secret.","images":[],"options":{"A":"off","B":"in","C":"away","D":"up"},"answer":"C","explanation":"The correct phrase to complete the sentence is 'gave away'. The sentence implies that the police officer was sacked because he revealed the command's secret. The phrasal verb 'give away' means to reveal or make known. 'Give off' means to emit a smell, light, heat, or a sound. 'Give in' means to surrender or yield. 'Give up' means to quit or surrender.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>63","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the word or group of words that best completes each of the following sentence.  He bought a new set of _______ television.","images":[],"options":{"A":"coloured","B":"colour","C":"colours","D":"colouring"},"answer":"B","explanation":"Colour television, photography, or printing shows things in all their colours, not just in black and white.","marks":"1","difficulty":"1"},{"id":"objective>English Language>2020>64","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the word or group of words that best completes each of the following sentence.  The newspaper reported that _______ everybody died in the accident.","images":[],"options":{"A":"hardly","B":"almost","C":"scarcely","D":"barely"},"answer":"B","explanation":"In the context of the sentence, the correct word is 'almost'. The word 'almost' is used to indicate that something is not completely the case but is very close to being so. The other options do not fit contextually in the sentence.","marks":"1","difficulty":"1"},{"id":"objective>English Language>2020>65","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : CLAUSES","question":"Choose the word or group of words that best completes each of the following sentence.  He isn't coming here, _______?","images":[],"options":{"A":"is he","B":"isn't he","C":"doesn't he","D":"does he"},"answer":"A","explanation":"In English, when a sentence is in negative form, the question tag that follows is in positive form. Therefore, 'is he' is the correct question tag for the sentence 'He isn't coming here'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>66","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : PHRASES","question":"Choose the word or group of words that best completes each of the following sentence.  _________ are often quite caring.","images":[],"options":{"A":"Mother-in- law","B":"Mother-in-laws","C":"Mothers-in-laws","D":"Mothers-in-law"},"answer":"D","explanation":"The correct plural form of 'mother-in-law' is 'mothers-in-law'. In compound nouns where the first word ends with '-in-law', the first word is the one that becomes plural.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>67","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : CLAUSES","question":"Choose the word or group of words that best completes each of the following sentence.  A spoilt child is usually prone _____ laziness.","images":[],"options":{"A":"to","B":"for","C":"with","D":"at"},"answer":"A","explanation":"To be prone to something is likely to suffer from an illness or show a particular negative characteristic.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>68","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : CLAUSES","question":"Choose the word or group of words that best completes each of the following sentence.  We do not accept the punishment _______ the boy.","images":[],"options":{"A":"meted to","B":"meted on","C":"meted out to","D":"meted in to"},"answer":"C","explanation":"To mete something out to somebody is to give or order a punishment or make someone receive cruel or unfair treatment.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>69","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : CLAUSES","question":"Choose the word or group of words that best completes each of the following sentence.  The team practised intensely for weeks before the match _______ it lost.","images":[],"options":{"A":"still yet","B":"for","C":"yet","D":"despite"},"answer":"C","explanation":"It means (and) despite that; used to add something that seems surprising because of what you have just said.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>70","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : CLAUSES","question":"Choose the word or group of words that best completes each of the following sentence.  You cannot come between my sister and ______.","images":[],"options":{"A":"Myself","B":"me","C":"I","D":"Mine"},"answer":"B","explanation":"The correct word to use in this context is 'me'. The sentence is using the object pronoun 'me' to refer to the speaker in the context of the preposition 'between'. 'Myself' is a reflexive pronoun and is used when the subject and the object of the sentence are the same person. 'I' is a subject pronoun and is used as the subject of a sentence. 'Mine' is a possessive pronoun and is used to show ownership.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>71","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the words that is most suitable to fill the number gaps in the passage.    Hardly a day passes without news of terrible accidents on our roads. Most of the time, these are caused by the ignorance and ____ of drivers.","images":[],"options":{"A":"Forgetfulness","B":"carelessness","C":"Wickedness","D":"Doubtfulness"},"answer":"B","explanation":"The most suitable word to fill the gap in the sentence is 'carelessness'. This is because the context of the sentence is talking about accidents caused by drivers. Carelessness is a common cause of accidents as it implies a lack of attention or consideration, which can lead to mistakes or accidents. The other options do not fit the context as well. 'Forgetfulness' implies a lack of memory, which is not directly related to causing accidents. 'Wickedness' implies evil intent, which is not a common cause of accidents. 'Doubtfulness' implies uncertainty, which is also not a common cause of accidents.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>72","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the words that is most suitable to fill the number gaps in the passage.  Besides the ignorance of the drivers, most of the vehicles that ply our roads are not ______. Vehicles are supposed to be tested annually before certificate are issued.","images":[],"options":{"A":"Road-friendly","B":"roadworthy","C":"Streetwise","D":"road-tested"},"answer":"B","explanation":"The most suitable word to fill the gap in the sentence is 'roadworthy'. This is because the context of the sentence is talking about the condition of vehicles. A vehicle is considered 'roadworthy' if it is in a suitable condition to be driven on the road, which is what the sentence is implying when it says that vehicles are supposed to be tested annually. The other options do not fit the context as well. 'Road-friendly' is not a term commonly used to describe vehicles. 'Streetwise' is a term used to describe someone who is savvy or knowledgeable about urban life, not a vehicle. 'Road-tested' implies that the vehicle has been tested on the road, but it does not necessarily mean that it is in a suitable condition to be driven.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>73","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the words that is most suitable to fill the number gaps in the passage.  However, vehicles owners are issued with these certificates even when their vehicles have not been properly _______.","images":[],"options":{"A":"scrutinised","B":"appraised","C":"considered","D":"inspected"},"answer":"D","explanation":"The correct word to fill the gap in the sentence is 'inspected'. This is because the context of the sentence is about vehicles and their certificates. The process of checking a vehicle's condition and ensuring it meets certain standards is referred to as 'inspection'. Therefore, the word 'inspected' is the most suitable among the options.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>74","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the words that is most suitable to fill the number gaps in the passage.  Most of the drives do not have a valid driver's _______.","images":[],"options":{"A":"document","B":"paper","C":"licence","D":"particulars"},"answer":"C","explanation":"The correct word to fill the gap in the sentence is 'licence'. This is because the context of the sentence is about drivers and their legal permission to drive. A driver's licence is a legal document that certifies that a person is qualified to drive a motor vehicle or vehicles. Therefore, the word 'licence' is the most suitable among the options.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>75","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the words that is most suitable to fill the number gaps in the passage.  There are driving schools with qualified ______ to prepare prospective drivers.","images":[],"options":{"A":"trainers","B":"instructors","C":"experts","D":"teachers"},"answer":"B","explanation":"In the context of driving schools, the term 'instructors' is most suitable. Instructors are individuals who teach specific skills, in this case, driving. Trainers, experts, and teachers could also teach, but in a driving school scenario, the term 'instructors' is more specific and appropriate.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>76","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the words that is most suitable to fill the number gaps in the passage.  There are driving schools with ______ cars to drive.","images":[],"options":{"A":"certified","B":"confirmed","C":"graded","D":"accredited"},"answer":"A","explanation":"In the context of driving schools, cars used for teaching are often 'certified'. This means they have been inspected and approved for use in teaching driving. The term 'certified' is more specific and appropriate in this context. 'Confirmed', 'graded', and 'accredited' are not typically used to describe cars in a driving school scenario.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>77","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the words that is most suitable to fill the number gaps in the passage.  Some drivers never even had a learners _____ when they were learning to drive.","images":[],"options":{"A":"permit","B":"clearance","C":"authority","D":"order"},"answer":"A","explanation":"The correct word to fill the gap in the sentence is 'permit'. A learner's permit is a restricted license that is given to a person who is learning to drive, but has not yet satisfied the requirements to obtain a driver's license. Having a learner's permit for a certain length of time is usually one of the requirements for applying for a full driver's license. To get a learner's permit, one must typically pass a written test about rules and regulations.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>78","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the words that is most suitable to fill the number gaps in the passage.  Consequently, they have no knowledge of  _____ rules.","images":[],"options":{"A":"expressway","B":"traffic","C":"highway","D":"road"},"answer":"B","explanation":"The correct word to fill the gap in the sentence is 'traffic'. Traffic rules are the laws or guidelines created by traffic authorities to regulate the movements of vehicles and pedestrians. These rules are made to ensure safety and to smooth functioning of traffic on the roads. When the question refers to 'knowledge of rules', it is most likely referring to traffic rules, as these are the rules that drivers must know and abide by.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>79","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the words that is most suitable to fill the number gaps in the passage.  They are ignorant of what speed ______ means.","images":[],"options":{"A":"distance","B":"control","C":"mileage","D":"limit"},"answer":"D","explanation":"In the context of the sentence, the word that fits best after 'speed' is 'limit'. A speed limit is a legal restriction on how fast one can drive in a certain area. The sentence implies that 'they' are not aware of what a speed limit means, suggesting they may drive too fast or too slow.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>80","subject":"English Language","year":"2020","type":"Objective","topic":"LEXIS : WORD CLASSES","question":"Choose the words that is most suitable to fill the number gaps in the passage.  To them, 100 kilometers per hour may mean minimum speed allowed. Little wonder the ______ on our roads.","images":[],"options":{"A":"murder","B":"scenes","C":"incidence","D":"accident"},"answer":"D","explanation":"In the context of the sentence, the word that fits best is 'accident'. The sentence implies that because people are driving at high speeds, there are accidents on the roads. The term 'accident' in this context refers to an unfortunate incident that happens unexpectedly and unintentionally, typically resulting in damage or injury.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>81","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : VOWELS","question":"Choose a word that has the same vowel sound(s) as the one represented by the letter(s) underlined.    Womb","images":[],"options":{"A":"book","B":"fool","C":"comb","D":"bomb"},"answer":"B","explanation":"Womb and fool both have the vowel /u:/. This best suits the question.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>82","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : VOWELS","question":"Choose a word that has the same vowel sound(s) as the one represented by the letter(s) underlined.  dirt","images":[],"options":{"A":"pet","B":"worth","C":"sword","D":"deed"},"answer":"B","explanation":"The vowel sound in 'dirt' is /\u025c:/ as in 'her'. The word 'worth' has the same vowel sound.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>83","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : VOWELS","question":"Choose a word that has the same vowel sound(s) as the one represented by the letter(s) underlined.  worst","images":[],"options":{"A":"fiery","B":"cord","C":"put","D":"worship"},"answer":"D","explanation":"Worst /w\u025c\u02d0st/    -worship /\u02c8w\u025c\u02d0\u0283\u026ap/. This best suits the question.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>84","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : VOWELS","question":"Choose a word that has the same vowel sound(s) as the one represented by the letter(s) underlined.  hall","images":[],"options":{"A":"Shortage","B":"love","C":"courage","D":"county"},"answer":"A","explanation":"The vowel sound represented by the underlined letter 'a' in the word 'hall' is /\u0254\u02d0/. The word 'shortage' has the same vowel sound.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>85","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : VOWELS","question":"Choose a word that has the same vowel sound(s) as the one represented by the letter(s) underlined.  pit","images":[],"options":{"A":"blight","B":"pious","C":"hatred","D":"paint"},"answer":"C","explanation":"Pit /p\u026at/ -hatred/\u02c8he\u026atr\u026ad/. This best suits the question.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>86","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : VOWELS","question":"Choose a word that has the same vowel sound(s) as the one represented by the letter(s) underlined.  pint","images":[],"options":{"A":"plait","B":"lisp","C":"buy","D":"late"},"answer":"C","explanation":"The word 'buy' has the same long 'i' sound as in 'pint'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>87","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : VOWELS","question":"Choose a word that has the same vowel sound(s) as the one represented by the letter(s) underlined.  Canoe","images":[],"options":{"A":"truce","B":"pull","C":"doe","D":"shore"},"answer":"A","explanation":"canoe/k\u0259\u02c8nu\u02d0/-truce /tru\u02d0s/. This best suits the question.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>88","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : VOWELS","question":"Choose a word that has the same vowel sound(s) as the one represented by the letter(s) underlined.  fatal","images":[],"options":{"A":"hard","B":"fat","C":"beard","D":"bail"},"answer":"D","explanation":"fatal/\u02c8fe\u026at(\u0259)l/-bail /be\u026al/. This best suits the question.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>89","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : VOWELS","question":"Choose a word that has the same vowel sound(s) as the one represented by the letter(s) underlined.  Jeopardy","images":[],"options":{"A":"check","B":"people","C":"probe","D":"fired"},"answer":"A","explanation":"jeopardy/\u02c8d\u0292\u025bp\u0259di/-check /t\u0283\u025bk/. This best suits the question.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>90","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : VOWELS","question":"Choose a word that has the same vowel sound(s) as the one represented by the letter(s) underlined.  stuff","images":[],"options":{"A":"tine","B":"hoof","C":"tough","D":"doff"},"answer":"C","explanation":"stuff /st\u028cf/-tough/t\u028cf/. This best suits the question.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>91","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : VOWELS","question":"Choose a word that has the same vowel sound(s) as the one represented by the letter(s) underlined.  Bear","images":[],"options":{"A":"her","B":"year","C":"fare","D":"pie"},"answer":"C","explanation":"The vowel sound in 'Bear' is /e\u0259/. The word 'fare' in the options has the same vowel sound.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>92","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : VOWELS","question":"Choose a word that has the same vowel sound(s) as the one represented by the letter(s) underlined.  boil","images":[],"options":{"A":"coy","B":"soul","C":"how","D":"mode"},"answer":"A","explanation":"The vowel sound in 'Boil' is /\u0254\u026a/. The word 'coy' in the options has the same vowel sound.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>93","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : VOWELS","question":"Choose a word that has the same vowel sound(s) as the one represented by the letter(s) underlined.  man","images":[],"options":{"A":"tape","B":"slash","C":"palm","D":"barn"},"answer":"B","explanation":"man /man/ - slash /sla\u0283/. This best suits the question.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>94","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : VOWELS","question":"Choose a word that has the same vowel sound(s) as the one represented by the letter(s) underlined.  heart","images":[],"options":{"A":"lust","B":"clear","C":"slash","D":"star"},"answer":"D","explanation":"heart/h\u0251\u02d0t/-star/st\u0251\u02d0/. This best suits the question.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>95","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : VOWELS","question":"Choose a word that has the same vowel sound(s) as the one represented by the letter(s) underlined.  Fault","images":[],"options":{"A":"brought","B":"bowl","C":"loan","D":"laugh"},"answer":"A","explanation":"fault/f\u0254\u02d0lt/-bought/b\u0254\u02d0t/. This best suits the question.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>96","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : CONSONANTS","question":"Choose a word that has the same consonant sound(s) as the one represented by the letter(s) underlined.    girl","images":[],"options":{"A":"badge","B":"gist","C":"bringing","D":"examine"},"answer":"D","explanation":"girl /\u0261\u025c\u02d0l/  -  examine /\u026a\u0261z\u00e6m\u026an/. This best suits the question.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>97","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : CONSONANTS","question":"Choose a word that has the same consonant sound(s) as the one represented by the letter(s) underlined.  height","images":[],"options":{"A":"house","B":"heir","C":"honest","D":"hour"},"answer":"A","explanation":"The \"h\" in house and height is pronounced as an audible breath while the \"h\" in the other options is silent.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>98","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : CONSONANTS","question":"Choose a word that has the same consonant sound(s) as the one represented by the letter(s) underlined.  pine","images":[],"options":{"A":"psalm","B":"push","C":"empty","D":"phone"},"answer":"B","explanation":"The word 'push' has the same consonant sound 'p' as in 'pine'. The other options either have a silent 'p', a 'p' sound that is not the initial sound, or an 'f' sound instead of a 'p' sound.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>99","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : CONSONANTS","question":"Choose a word that has the same consonant sound(s) as the one represented by the letter(s) underlined.  most","images":[],"options":{"A":"sniffed","B":"though","C":"think","D":"listen"},"answer":"A","explanation":"most /m\u0259\u028ast/ - sniffed /sn\u026aft  The \"t\" in listen is silent.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>100","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : CONSONANTS","question":"Choose a word that has the same consonant sound(s) as the one represented by the letter(s) underlined.  zoo","images":[],"options":{"A":"stature","B":"cease","C":"days","D":"leisure"},"answer":"C","explanation":"zoo /zu:/ - days /de\u026az  The \"s\" in cease, stature and lesiure are pronounced differently.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>101","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : CONSONANTS","question":"Choose a word that has the same consonant sound(s) as the one represented by the letter(s) underlined.  bath","images":[],"options":{"A":"heart","B":"those","C":"bathe","D":"thigh"},"answer":"D","explanation":"bath /b\u0251\u02d0\u03b8/  heart /h\u0251\u02d0t/  those /\u00f0\u0259\u028az/  bathe /be\u026a\u00f0/  thigh /thigh/","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>102","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : CONSONANTS","question":"Choose a word that has the same consonant sound(s) as the one represented by the letter(s) underlined.  band","images":[],"options":{"A":"breath","B":"asked","C":"handsome","D":"dream"},"answer":"D","explanation":"The 'd' in 'band' is a voiced alveolar stop, represented by /d/ in the International Phonetic Alphabet (IPA). The word 'dream' has the same consonant sound.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>103","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : CONSONANTS","question":"Choose a word that has the same consonant sound(s) as the one represented by the letter(s) underlined.  archive","images":[],"options":{"A":"challenge","B":"match","C":"chimera","D":"chime"},"answer":"C","explanation":"archive /\u0251\u02d0ka\u026av/  challenge /t\u0283\u00e6l\u026and\u0292/  match /m\u00e6t\u0283/  chimera /ka\u026am\u026a\u0259r\u0259/  chime /t\u0283a\u026am/","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>104","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : CONSONANTS","question":"Choose a word that has the same consonant sound(s) as the one represented by the letter(s) underlined.  swine","images":[],"options":{"A":"one","B":"new","C":"know","D":"seen"},"answer":"A","explanation":"swine /swa\u026an/  one /w\u028cn/  new /nju\u02d0/  know /n\u0259\u028a/  seen /si\u02d0n/","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>105","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : CONSONANTS","question":"Choose a word that has the same consonant sound(s) as the one represented by the letter(s) underlined.  base","images":[],"options":{"A":"boys","B":"clash","C":"lace","D":"lazy"},"answer":"C","explanation":"base /be\u026as/  boys /b\u0254\u026az  clash /kl\u00e6\u0283/  lace /le\u026as/  lazy /le\u026azi/","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>106","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : CONSONANTS","question":"Choose a word that has the same consonant sound(s) as the one represented by the letter(s) underlined.  wept","images":[],"options":{"A":"castle","B":"apostle","C":"slapped","D":"passed"},"answer":"C","explanation":"The 'pt' in 'wept' has a /pt/ sound. The word 'slapped' also has the same /pt/ sound.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>107","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : CONSONANTS","question":"Choose a word that has the same consonant sound(s) as the one represented by the letter(s) underlined.  card","images":[],"options":{"A":"sandwich","B":"hedge","C":"soldier","D":"maiden"},"answer":"D","explanation":"card /k\u0251\u02d0d/  sandwich /s\u00e6nw\u026at\u0283/  hedge /hed\u0292/  soldier /s\u0259\u028ald\u0292\u0259/  maiden /me\u026ad\u0259n/","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>108","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : CONSONANTS","question":"Choose a word that has the same consonant sound(s) as the one represented by the letter(s) underlined.  fetch","images":[],"options":{"A":"approve","B":"tough","C":"thorough","D":"believe"},"answer":"B","explanation":"fetch /fet\u0283/  approve /\u0259pru\u02d0v/  tough /t\u028cf/  thorough /\u03b8\u028cr\u0259/  believe /b\u026ali\u02d0v/","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>109","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : CONSONANTS","question":"Choose a word that has the same consonant sound(s) as the one represented by the letter(s) underlined.  arrest","images":[],"options":{"A":"lure","B":"shirt","C":"rule","D":"spurn"},"answer":"C","explanation":"The sound of 'rr' in 'arrest' is /r/. The word 'rule' also has the /r/ sound.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>110","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : CONSONANTS","question":"Choose a word that has the same consonant sound(s) as the one represented by the letter(s) underlined.  writes","images":[],"options":{"A":"wards","B":"costs","C":"wins","D":"dines"},"answer":"B","explanation":"The sound of 'tes' in 'writes' is /ts/. The word 'costs' also has the /ts/ sound.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>111","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : RHYMES","question":"Choose the word that rhymes with the given word.    suite","images":[],"options":{"A":"thrice","B":"suit","C":"sweet","D":"sweat"},"answer":"C","explanation":"The word 'suite' rhymes with 'sweet'. Rhyming words are words that have the same ending sounds. In this case, 'suite' and 'sweet' both end with the '-eet' sound.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>112","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : RHYMES","question":"Choose the word that rhymes with the given word.  incite","images":[],"options":{"A":"inside","B":"disquiet","C":"excite","D":"surmise"},"answer":"C","explanation":"The word 'incite' rhymes with 'excite'. Rhyming words are words that have the same ending sounds. In this case, 'incite' and 'excite' both end with the '-ite' sound.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>113","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : RHYMES","question":"Choose the word that rhymes with the given word.  flood","images":[],"options":{"A":"chord","B":"cud","C":"curd","D":"call"},"answer":"B","explanation":"Rhyming words are words that have the same ending sounds. The word 'flood' rhymes with 'cud' because they both have the same '-ud' ending sound.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>114","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : RHYMES","question":"Choose the word that rhymes with the given word.  receipt","images":[],"options":{"A":"unkempt","B":"dealt","C":"deceit","D":"leapt"},"answer":"C","explanation":"The words receipt and deceit rhyme. This is the accurate answer","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>115","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : RHYMES","question":"Choose the word that rhymes with the given word.  firm","images":[],"options":{"A":"born","B":"worm","C":"burn","D":"girl"},"answer":"B","explanation":"The word 'firm' rhymes with 'worm'. Rhyming words are words that have the same ending sounds. In this case, 'firm' and 'worm' both end with the 'erm' sound.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>116","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : WORD STRESS/SYLLABLE STRUCTURE","question":"Choose the syllable that has the correct stress.    overwhelming","images":[],"options":{"A":"O-ver-whelm-ing","B":"o-VER-whelm-ing","C":"o-ver-WHELM-ing","D":"o-ver-whelm-ING"},"answer":"C","explanation":"In the word 'overwhelming', the stress falls on the third syllable 'WHELM'. In English, stress is the relative emphasis that may be given to certain syllables in a word, or to certain words in a phrase or sentence. The option 'o-ver-WHELM-ing' correctly represents this stress pattern.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>117","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : WORD STRESS/SYLLABLE STRUCTURE","question":"Choose the syllable that has the correct stress.  melancholy","images":[],"options":{"A":"MEL-an-chol-y","B":"mel-AN-chol-y","C":"mel-an-CHOL-y","D":"mel-an-chol-Y"},"answer":"A","explanation":"In English language, stress is the emphasis that is given to particular syllables in words. The word 'melancholy' is stressed on the first syllable, hence the correct option is 'MEL-an-chol-y'.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>118","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : WORD STRESS/SYLLABLE STRUCTURE","question":"Choose the syllable that has the correct stress.  inflammation","images":[],"options":{"A":"IN-flam-ma-tion","B":"in-FLAM-ma-tion","C":"in-flam-MA-tion","D":"in-flam-ma-TION"},"answer":"C","explanation":"INFLAMMATION      =     in-flam- MA-tion. This is the accurate answer","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>119","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : WORD STRESS/SYLLABLE STRUCTURE","question":"Choose the syllable that has the correct stress.  calculation","images":[],"options":{"A":"CAL-cu-la-tion","B":"cal-CU-la-tion","C":"cal-cu-LA-tion","D":"cal-cu-la-TION"},"answer":"C","explanation":"CALCULATION          =     cal-cu-LA-tion. This is the accurate answer","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>120","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : WORD STRESS/SYLLABLE STRUCTURE","question":"Choose the syllable that has the correct stress.  economic","images":[],"options":{"A":"EC-o-nom-ic","B":"ec-O-nom-ic","C":"ec-o-NOM-ic","D":"ec-o-nom-IC"},"answer":"C","explanation":"ECONOMIC               =      ec-o-NOM-ic. This is the accurate answer","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>121","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : WORD STRESS/SYLLABLE STRUCTURE","question":"Choose the syllable that has the correct stress.  All the words except one has the same stree pattern. Identify the one with the different stress pattern","images":[],"options":{"A":"undo","B":"ado","C":"unless","D":"legal"},"answer":"D","explanation":"LE-gal has it stress on the first syllable while others have theirs on the second syllable,e.g ado= a-DO, undo= un-DO.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>122","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : WORD STRESS/SYLLABLE STRUCTURE","question":"Choose the syllable that has the correct stress.","images":[],"options":{"A":"despite","B":"petrol","C":"wardrobe","D":"vomit"},"answer":"A","explanation":"de-SPITE has it stress on the second syllable while others have theirs on the first syllable, e.g petrol= PET-rol, vomit= VO-mit.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>123","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : WORD STRESS/SYLLABLE STRUCTURE","question":"Choose the syllable that has the correct stress.","images":[],"options":{"A":"typist","B":"orphan","C":"mattress","D":"cigar"},"answer":"D","explanation":"ci-GAR has it stress on the second syllable while others have theirs on the first syllables,e.g MAT-tress, OR-phan.","marks":"1","difficulty":"1"},{"id":"objective>English Language>2020>124","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : WORD STRESS/SYLLABLE STRUCTURE","question":"Choose the syllable that has the correct stress.","images":[],"options":{"A":"colleague","B":"beauty","C":"extent","D":"success"},"answer":"B","explanation":"In English language, the word 'beauty' has the stress on the first syllable. The other options do not have the stress on the correct syllable.","marks":"1","difficulty":"1"},{"id":"objective>English Language>2020>125","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : WORD STRESS/SYLLABLE STRUCTURE","question":"Choose the syllable that has the correct stress.","images":[],"options":{"A":"formative","B":"character","C":"designate","D":"continue"},"answer":"D","explanation":"con-TI-nue has it stress on the second syllable while other words have theirs on the first syllable.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>126","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : EMPHATIC STRESS/INTONATION PATTERNS","question":"In each of the following sentences, the word that receives the emphatic stress is written in capital letter. From the letter A-D, choose the one to which the given sentence is the appropriate answer.    The man BROUGHT the newspaper.","images":[],"options":{"A":"Did the woman bring the newspaper?","B":"Did the man bring a newspaper?","C":"Did the man bring the magazine?","D":"Did the man read the newspaper?"},"answer":"D","explanation":"The answer is the sentence which has a word contrasting the focus word BROUGHT.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>127","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : EMPHATIC STRESS/INTONATION PATTERNS","question":"In each of the following sentences, the word that receives the emphatic stress is written in capital letter. From the letter A-D, choose the one to which the given sentence is the appropriate answer.  The woman wants MY car.","images":[],"options":{"A":"Does the woman want my radio?","B":"Does the man want my car?","C":"Does the woman want the car?","D":"Does the woman need my car"},"answer":"C","explanation":"The sentence 'The woman wants MY car.' is emphasizing the object 'my car'. The question that would elicit this response is 'Does the woman want the car?' because it is asking about the same object that is being emphasized in the response.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>128","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : EMPHATIC STRESS/INTONATION PATTERNS","question":"In each of the following sentences, the word that receives the emphatic stress is written in capital letter. From the letter A-D, choose the one to which the given sentence is the appropriate answer.  The president SPOKE to the press yesterday.","images":[],"options":{"A":"Did the minister speak to the press yesterday?","B":"Did the president speak to the lecturers yesterday?","C":"Did the president wave to the press yesterday?","D":"Did the press speak to the press today?"},"answer":"C","explanation":"The answer is the sentence which has a word contrasting the focus word SPOKE.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>129","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : EMPHATIC STRESS/INTONATION PATTERNS","question":"In each of the following sentences, the word that receives the emphatic stress is written in capital letter. From the letter A-D, choose the one to which the given sentence is the appropriate answer.  Comfort prepared a DELICIOUS meal.","images":[],"options":{"A":"Did comfort prepare a delicious meal?","B":"Did comfort prepare a tasteless meal?","C":"Did jummy prepare a delicious meal?","D":"Did comfort order a delicious meal?"},"answer":"B","explanation":"The answer is the sentence which has a word contrasting the focus word DELICIOUS.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>130","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : EMPHATIC STRESS/INTONATION PATTERNS","question":"In each of the following sentences, the word that receives the emphatic stress is written in capital letter. From the letter A-D, choose the one to which the given sentence is the appropriate answer.  OUR Mathematics teacher has been transferred.","images":[],"options":{"A":"Has their Mathematics teacher been transferred?","B":"Has our physics teacher been transferred?","C":"Has our mathematics teacher been promoted?","D":"Has our Mathematics supervisor been transferred?"},"answer":"A","explanation":"The question 'Has their Mathematics teacher been transferred?' is the appropriate answer to the given sentence 'OUR Mathematics teacher has been transferred.' because it emphasizes the same word 'OUR' as in the given sentence. Emphatic stress in English language is used to place focus on a particular word in a sentence to give it more importance or to express contrast.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>131","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : VOWELS","question":"Choose the word that contains the sound represented by the given phonetics symbol    /a\u026as/","images":[],"options":{"A":"rare","B":"ice","C":"air","D":"fuel"},"answer":"B","explanation":"The phonetic symbol /a\u026as/ represents the sound in the word 'ice'. Phonetics is the study of the physical sounds of human speech. It is concerned with the physical properties of speech sounds (also known as phonemes), and the processes of their physiological production, auditory reception, and neurophysiological perception.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>132","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : VOWELS","question":"Choose the word that contains the sound represented by the given phonetics symbol  /\u00e6/","images":[],"options":{"A":"bag","B":"park","C":"get","D":"class"},"answer":"A","explanation":"The phonetic symbol /\u00e6/ represents the sound in the word 'bag'. Phonetics is the study of the physical sounds of human speech. It is concerned with the physical properties of speech sounds (also known as phonemes), and the processes of their physiological production, auditory reception, and neurophysiological perception.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>133","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : CONSONANTS","question":"Choose the word that contains the sound represented by the given phonetics symbol  /d/","images":[],"options":{"A":"handkerchief","B":"passed","C":"handsome","D":"bride"},"answer":"D","explanation":"The word bride is pronounced /bra\u026ad/. The \"d\" in the other options is either silent or pronounced differently.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>134","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : VOWELS","question":"Choose the word that contains the sound represented by the given phonetics symbol  /e/","images":[],"options":{"A":"bite","B":"leave","C":"spare","D":"heaven"},"answer":"D","explanation":"The word heaven is pronounced /hev\u0259n/. The \"e\" in the other options is silent.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>135","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : VOWELS","question":"Choose the word that contains the sound represented by the given phonetics symbol  /\u0252/","images":[],"options":{"A":"bore","B":"warp","C":"wander","D":"wonder"},"answer":"C","explanation":"The word wander is pronounced /w\u0252nd\u0259/. Both bore and warp contain vowel /\u0254\u02d0/ while wonder contains vowel /\u028c/.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>136","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : CONSONANTS","question":"Choose the word that contains the sound represented by the given phonetics symbol  /k/","images":[],"options":{"A":"civil","B":"choral","C":"chore","D":"choose"},"answer":"B","explanation":"The word choral contains consonant /k/ while the \"c\" in the other options is pronounced differently.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>137","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : CONSONANTS","question":"Choose the word that contains the sound represented by the given phonetics symbol  /g/","images":[],"options":{"A":"gnash","B":"target","C":"gnaw","D":"sing"},"answer":"B","explanation":"The word target is pronounced /t\u0251\u02d0\u0261\u026at/ while the \"g\" in gnash and gnaw is silent. The \"g\" in sing combines with the \"n\" to produce /\u014b/.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>138","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : VOWELS","question":"Choose the word that contains the sound represented by the given phonetics symbol  /u:/","images":[],"options":{"A":"work","B":"grew","C":"teeth","D":"bull"},"answer":"B","explanation":"The phonetic symbol /u:/ represents a long close back rounded vowel, which is the sound made by 'ew' in 'grew'. The other options do not contain this sound.","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>139","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : CONSONANTS","question":"Choose the word that contains the sound represented by the given phonetics symbol  /\u222b/","images":[],"options":{"A":"badge","B":"catch","C":"bastion","D":"edition"},"answer":"D","explanation":"badge /b\u00e6d\u0292/  catch /k\u00e6t\u0283/  bastion /b\u00e6sti\u0259n/  edition /\u026ad\u026a\u0283\u0259n/","marks":"1","difficulty":"2"},{"id":"objective>English Language>2020>140","subject":"English Language","year":"2020","type":"Objective","topic":"TEST OF ORALS : CONSONANTS","question":"Choose the word that contains the sound represented by the given phonetics symbol  /\u014b/","images":[],"options":{"A":"know","B":"chance","C":"lean","D":"living."},"answer":"D","explanation":"The \"n\" in living combines with the \"g\" to make /\u014b/ while the \"n\" in the other options is pronounced /n/.","marks":"1","difficulty":"2"}];